                        // Check if other operand is zero
                        if ((a_exponent[7:0] == 8'h00 && a_mantissa[22:0] == 23'd0) ||
                            (b_exponent[7:0] == 8'h00 && b_mantissa[22:0] == 23'd0)) begin
                            // Infinity * 0 = NaN
                            z <= 32'hFFC00000;
                        end else begin
                            // Result is infinity
                            z <= {a_sign ^ b_sign, 8'hFF, 23'd0};
                        end
                        counter <= 3'd0;
                    end
                    // Check for zero
                    else if ((a_exponent[7:0] == 8'h00 && a_mantissa[22:0] == 23'd0) ||
                             (b_exponent[7:0] == 8'h00 && b_mantissa[22:0] == 23'd0)) begin
                        // Result is zero
                        z <= {a_sign ^ b_sign, 31'd0};
                        counter <= 3'd0;
