module div_16bit(
    input [15:0] A,
    input [7:0] B,
    output [15:0] result,
    output [15:0] odd
);

    reg [15:0] a_reg;
    reg [7:0] b_reg;
    reg [15:0] result_reg;
    reg [15:0] odd_reg;

    // First always block: update registers with input values
    always @(*) begin
        a_reg = A;
        b_reg = B;
    end

    // Second always block: perform division
    always @(*) begin
        reg [7:0] remainder;
        reg [15:0] quotient;
        integer i;

        remainder = 8'b0;
        quotient = 16'b0;

        // Process each bit of the dividend from MSB to LSB
        for (i = 15; i >= 0; i = i - 1) begin
            // Shift remainder left by 1 and bring in next bit of dividend
            remainder = {remainder[6:0], a_reg[i]};

            // Compare remainder with divisor
            if (remainder >= b_reg) begin
                quotient[i] = 1'b1;
                remainder = remainder - b_reg;
            end else begin
                quotient[i] = 1'b0;
            end
        end

        result_reg = quotient;
        odd_reg = {8'b0, remainder};
    end

    assign result = result_reg;
    assign odd = odd_reg;

endmodule

