module fsm(
    input IN,
    input CLK,
    input RST,
    output MATCH
);

    // State encoding
    parameter S0 = 3'd0; // Initial state
    parameter S1 = 3'd1; // Received '1'
    parameter S2 = 3'd2; // Received '10'
    parameter S3 = 3'd3; // Received '100'
    parameter S4 = 3'd4; // Received '1001'
    parameter S5 = 3'd5; // Received '10011' (match)

    reg [2:0] current_state, next_state;

    // State register
    always @(posedge CLK or posedge RST) begin
        if (RST) begin
            current_state <= S0;
        end else begin
            current_state <= next_state;
        end
    end

    // Next state logic (Mealy FSM)
    always @(*) begin
        case (current_state)
            S0: begin
                if (IN == 1'b1)
                    next_state = S1;
                else
                    next_state = S0;
            end
            S1: begin
                if (IN == 1'b0)
                    next_state = S2;
                else
                    next_state = S1; // Stay in S1 if another '1'
            end
            S2: begin
                if (IN == 1'b0)
                    next_state = S3;
                else
                    next_state = S1; // Got '1', restart from S1
            end
            S3: begin
                if (IN == 1'b1)
                    next_state = S4;
                else
                    next_state = S0; // Got '0', restart
            end
            S4: begin
                if (IN == 1'b1)
                    next_state = S5;
                else
                    next_state = S2; // Got '0', overlap: '10011' + '0' -> check for '100'
            end
            S5: begin
                // After match, check for overlapping sequences
                // '10011' detected, next input:
                // If '1' -> could be start of new sequence at S1
                // If '0' -> '100110' -> S2 (we have '10')
                if (IN == 1'b0)
                    next_state = S2; // '100110' -> last '10' matches start
                else
                    next_state = S1; // '100111' -> last '1' matches start
            end
            default: next_state = S0;
        endcase
    end

    // Output logic (Mealy: based on current state and input)
    assign MATCH = (RST) ? 1'b0 : 
                   ((current_state == S4) && (IN == 1'b1)) ? 1'b1 : 1'b0;

endmodule

