module sequence_detector(
    input clk,
    input reset_n,
    input data_in,
    output sequence_detected,
    output IDLE,
    output S1,
    output S2,
    output S3,
    output S4
);

    // State encoding
    parameter STATE_IDLE = 3'd0;
    parameter STATE_S1   = 3'd1;
    parameter STATE_S2   = 3'd2;
    parameter STATE_S3   = 3'd3;
    parameter STATE_S4   = 3'd4;

    reg [2:0] current_state, next_state;

    // State register
    always @(posedge clk or negedge reset_n) begin
        if (!reset_n)
            current_state <= STATE_IDLE;
        else
            current_state <= next_state;
    end

    // Next state logic
    always @(*) begin
        case (current_state)
            STATE_IDLE: begin
                if (data_in == 1'b1)
                    next_state = STATE_S1;
                else
                    next_state = STATE_IDLE;
            end
            STATE_S1: begin
                if (data_in == 1'b0)
                    next_state = STATE_S2;
                else
                    next_state = STATE_S1;
            end
            STATE_S2: begin
                if (data_in == 1'b0)
                    next_state = STATE_S3;
                else
                    next_state = STATE_S1;
            end
            STATE_S3: begin
                if (data_in == 1'b1)
                    next_state = STATE_S4;
                else
                    next_state = STATE_IDLE;
            end
            STATE_S4: begin
                if (data_in == 1'b1)
                    next_state = STATE_S1;
                else
                    next_state = STATE_S2;
            end
            default: next_state = STATE_IDLE;
        endcase
    end

    // Output logic
    assign sequence_detected = (current_state == STATE_S4);
    assign IDLE = (current_state == STATE_IDLE);
    assign S1   = (current_state == STATE_S1);
    assign S2   = (current_state == STATE_S2);
    assign S3   = (current_state == STATE_S3);
    assign S4   = (current_state == STATE_S4);

endmodule

