module LIFObuffer(
    input [3:0] dataIn,
    input RW,
    input EN,
    input Rst,
    input Clk,
    output reg EMPTY,
    output reg FULL,
    output reg [3:0] dataOut
);

    reg [3:0] stack_mem [0:3];
    reg [2:0] SP; // Stack pointer (0-4, where 4 means empty)

    integer i;

    always @(posedge Clk) begin
        if (EN) begin
            if (Rst) begin
                SP <= 4;
                dataOut <= 4'b0000;
                for (i = 0; i < 4; i = i + 1) begin
                    stack_mem[i] <= 4'b0000;
                end
                EMPTY <= 1'b1;
                FULL <= 1'b0;
            end
            else begin
                if (RW == 1'b0) begin // Write operation (push)
                    if (!FULL) begin
                        SP <= SP - 1;
                        stack_mem[SP - 1] <= dataIn;
                    end
                end
                else begin // Read operation (pop)
                    if (!EMPTY) begin
                        dataOut <= stack_mem[SP];
                        stack_mem[SP] <= 4'b0000;
                        SP <= SP + 1;
                    end
                end

                // Update flags
                if (SP == 4) begin
                    EMPTY <= 1'b1;
                    FULL <= 1'b0;
                end
                else if (SP == 0) begin
                    EMPTY <= 1'b0;
                    FULL <= 1'b1;
                end
                else begin
                    EMPTY <= 1'b0;
                    FULL <= 1'b0;
                end
            end
        end
    end

endmodule

