module freq_divbyfrac(
    input clk,
    input rst_n,
    output clk_div
);

    // Parameter for 3.5x division (2 * 3.5 = 7)
    parameter MUL2_DIV_CLK = 7;

    // Counter
    reg [2:0] cnt;

    // Intermediate clock signals
    reg clk_div1;  // Divided clock on positive edge
    reg clk_div2;  // Divided clock on negative edge (phase shifted)

    // Counter logic - counts from 0 to MUL2_DIV_CLK-1
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 3'd0;
        end else begin
            if (cnt == MUL2_DIV_CLK - 1)
                cnt <= 3'd0;
            else
                cnt <= cnt + 3'd1;
        end
    end

    // Generate clk_div1 based on positive edge of clk
    // High for 4 cycles (0,1,2,3), Low for 3 cycles (4,5,6)
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            clk_div1 <= 1'b0;
        end else begin
            if (cnt == 3'd0)
                clk_div1 <= 1'b1;
            else if (cnt == 3'd3)
                clk_div1 <= 1'b0;
            else if (cnt == MUL2_DIV_CLK - 1)
                clk_div1 <= 1'b1;
        end
    end

    // Generate clk_div2 based on negative edge of clk (half period shift)
    // This creates a phase-shifted version
    always @(negedge clk or negedge rst_n) begin
        if (!rst_n) begin
            clk_div2 <= 1'b0;
        end else begin
            if (cnt == 3'd0)
                clk_div2 <= 1'b1;
            else if (cnt == 3'd3)
                clk_div2 <= 1'b0;
            else if (cnt == MUL2_DIV_CLK - 1)
                clk_div2 <= 1'b1;
        end
    end

    // OR the two clocks to produce the final fractional divided clock
    assign clk_div = clk_div1 | clk_div2;

endmodule

