    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 3'd0;
        end else begin
            if (cnt == MUL2_DIV_CLK - 1)
                cnt <= 3'd0;
            else
                cnt <= cnt + 1'b1;
        end
    end

    // Generate clk_div1 on positive edge
    // High for 4 cycles (0,1,2,3), Low for 3 cycles (4,5,6)
    // This creates uneven duty cycle
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            clk_div1 <= 1'b0;
        end else begin
            if (cnt == 3'd0)
                clk_div1 <= 1'b1;
            else if (cnt == 3'd3)  // After 4 high cycles, go low
                clk_div1 <= 1'b0;
        end
    end

    // Generate clk_div2 on negative edge (phase shifted by half clock)
    // This is the same pattern but sampled on falling edge
    always @(negedge clk or negedge rst_n) begin
        if (!rst_n) begin
            clk_div2 <= 1'b0;
        end else begin
            if (cnt == 3'd0)
                clk_div2 <= 1'b1;
            else if (cnt == 3'd3)
                clk_div2 <= 1'b0;
        end
    end

    // OR the two clocks to get the final fractional divided clock
    assign clk_div = clk_div1 | clk_div2;

endmodule
